<script setup lang="ts">import { computed,onMounted } from 'vue';import { useRoute } from 'vue-router';import { world } from '../store/world';const route=useRoute();const teamId=computed(()=>Number(route.params.teamId||0));onMounted(async()=>{if(teamId.value)await world.loadTeam(teamId.value);else await world.loadTeams();});</script>
<template><div class="page archive-page"><header class="page-heading"><div><span class="eyebrow">问策卷宗</span><h1>历次推演</h1><p>后端 Run Archive 接口上线后，这里将展示可检索、可追溯的历史问策。当前提供现行任务快照入口。</p></div></header><section class="panel archive-placeholder"><span class="scroll-icon" aria-hidden="true">卷</span><h2>{{world.state.run?'当前卷宗已在案':'卷库尚待接通'}}</h2><p v-if="world.state.run">任务编号 {{world.state.run.id}} · 进度 {{world.state.run.progress}}% · {{world.state.run.source==='fallback'?'兼容聚合':'原生 Run'}}</p><RouterLink v-if="world.state.run&&teamId" :to="{name:'run',params:{teamId,runId:world.state.run.id}}">查看当前卷宗</RouterLink><p v-else>计划接口：<code>GET /runs?team_id=…</code>。页面不会伪造历史数据。</p></section></div>
</template>
